  ('social-worker-moex-07050', 'social-worker', 'social-worker-moex-101-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據Kübler-Ross的研究顯示，一般人面對死亡階段大約會經歷下列那種順序的階段？', '["否認與孤獨→憂鬱→討價還價→憤怒→接受", "否認與孤獨→憤怒→討價還價→憂鬱→接受", "憤怒→否認與孤獨→憂鬱→討價還價→接受", "憂鬱→否認與孤獨→憤怒→討價還價→接受"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "0b336dc02022", "answer_pdf_sha1": "b9eb953e36b8", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
